import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";

export default function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const submit = async (e) => {
    e.preventDefault();
    setError("");
    // demo-only auth; replace with API later
    await new Promise((r) => setTimeout(r, 300));
    if (email === "admin@gmail.com" && password === "admin") {
      navigate("/dashboard", { replace: true });
    } else {
      setError("Wrong credentials");
    }
  };

  return (
    <div className="g-auth-bg">
      <div className="g-auth-card">
        <div className="g-auth-logo">
          <span className="g-dot g-blue" />
          <span className="g-dot g-red" />
          <span className="g-dot g-yellow" />
          <span className="g-dot g-green" />
          <span className="g-brand">NeuroFleetX</span>
        </div>
        <h1 className="g-title">Sign in</h1>
        <p className="g-subtitle">Use your account</p>

        {error && <div className="g-error">{error}</div>}

        <form className="g-form" onSubmit={submit}>
          <div className="g-field">
            <input
              className="g-input"
              type="email"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              autoComplete="username"
              required
            />
          </div>
          <div className="g-field">
            <input
              className="g-input"
              type="password"
              placeholder="Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              autoComplete="current-password"
              required
            />
          </div>
          <div className="g-actions">
            <button className="g-btn" type="submit">Sign in</button>
          </div>
        </form>

        <div className="g-help">
          <Link to="/signup">Sign up</Link>
        </div>
      </div>
    </div>
  );
}
